def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 10:
            for a in range(10, 5, -1):
                for b in range(1, a + 4):
                    val = (ratio - a)**6 / (a * b * 1.1 + 0.7) * np.sin(ratio * b / (a + 2))
                    priority += val * np.exp(-0.1 * i)
            priority += (np.cosh(ratio - 10) * np.sin(ratio * 1.3)) ** 2
            for c in range(3):
                priority += np.log1p(bin_cap + c) * np.tanh(ratio / (c + 1))
        elif 6 < ratio <= 10:
            sum1 = 0
            for m in range(1, int(np.ceil(ratio)) + 5):
                for n in range(1, m + 3):
                    factor = ((ratio - m) ** 4) * np.cos(ratio * n) / (n + 1.2)
                    sum1 += np.tanh(factor) * 1.5
            priority += sum1 + np.exp(-ratio / 2) * 15
            if i % 2 == 0:
                priority += np.sin(ratio * i * 0.9) * 3
            else:
                priority -= np.cos(ratio * i * 1.2) * 3
        elif 3 < ratio <= 6:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 3) ** r) / (r * 2.1) * np.cos(r * ratio * 0.7)
            priority = s * np.cos(5 * ratio) - np.log(ratio) * 7 + np.tanh(5 * (6 - ratio)) * 2
            for z in range(2, 8):
                priority += np.sin(z * ratio * i) / (z + 0.3)
        elif 1 < ratio <= 3:
            s = 0
            for p in range(1, 14):
                s += ((3 - ratio) ** p) / (p ** 1.5 + 0.5) * np.sin(p * ratio)
            if bin_cap < item * 1.25:
                penalty = np.sqrt(item / (bin_cap + 0.3)) * 5
            else:
                penalty = np.cos(15 * ratio) * 3
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for q in range(1, 6):
                priority += np.sin(q * ratio * (i + 1)) * ((ratio - 1) ** q) / (q + 0.5)
        elif 0.5 <= ratio < 1:
            s = 0
            for j in range(1, 20):
                s += ((1 - ratio) ** j) / (j * 3.5) * np.cos(j * item * 0.8)
            priority = s
            if (i * int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 1) + 3)
            for k in range(1, 7):
                priority += ((1 - ratio) ** k) * np.sin(k * item * 1.5) * 0.9
        elif 0.2 <= ratio < 0.5:
            s = 0
            for l in range(1, 18):
                s += ((0.5 - ratio) ** l) / (l * 5) * np.cos(l * ratio * 1.5)
            priority = s + 1 / (bin_cap + 2)
            if int(item * 1.7) % 3 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.8) * 4.5
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for n in range(1, 15):
                s += ((0.2 - ratio) ** n) / (n * 8) * np.sin(n * item * 1.1)
            priority = s + 3 / (bin_cap + 3)
            if int(item * 0.8) % 6 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.1:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for o in range(1, 10):
                priority += ((0.2 - ratio) ** o) / (o * 9) * np.cos(item * o * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2.5 * bin_cap) * 6
        elif bin_cap > item * 3:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 5 == 0:
                priority += np.sin(ratio * (i + idx) * 1.1) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.1) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        priorities[i] = priority
    return priorities
